        ]

        let localVariableHeaderParameters = APIHelper.rejectNilHeaders(localVariableNillableHeaders)

        let localVariableRequestBuilder: RequestBuilder<GetEntitlements200Response>.Type = apiConfiguration.requestBuilderFactory.getBuilder()

